from dataclasses import dataclass, field
from typing import List

@dataclass
class ArticleAuditResult:
    article_id: str
    title: str
    issues: List[str] = field(default_factory=list)
    action: str = "keep"  # keep | update | retire | rewrite

def audit_article(article: dict, all_article_ids: set) -> ArticleAuditResult:
    result = ArticleAuditResult(
        article_id=article["id"],
        title=article["title"],
    )

    # Check: internal links still resolve
    for link in article.get("internal_links", []):
        if link not in all_article_ids:
            result.issues.append(f"Broken internal link: {link}")

    # Check: article has at least one heading
    if "<h2" not in article.get("content", ""):
        result.issues.append("No subheadings — difficult to scan")

    # Check: reading level is appropriate (Flesch-Kincaid proxy: word count / sentence count > 25 = complex)
    word_count = len(article.get("content", "").split())
    if word_count > 2000:
        result.issues.append(f"Article is long ({word_count} words) — consider splitting")

    # Determine action
    if article.get("freshness_score", 100) < 20:
        result.action = "retire"
    elif len(result.issues) > 3:
        result.action = "rewrite"
    elif result.issues:
        result.action = "update"

    return result
